var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"중간 보고 드립니다.","JPN":"中間報告です。","ENG":"Interim report.","TWN":"中間情況報告。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이제 곧 마타도르를 따라잡을 수 있을 것 같아요.","JPN":"間もなくマタドールに追いつくことができそうです。","ENG":"Soon, we'll catch up to the Matador.","TWN":"應該很快就能抓到目標對象！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"조금 전부터 통신망에 스캐빈저의 다이브 신호를 포착했다는 소식이 끊이질 않고 있어요. ","JPN":"先ほどから通信レーダーにスカベンジャーのダイブ信号を捉えたというアラートが絶えません。","ENG":"Everyone on the communication network is saying that they've detected the Scavengers' Dive signals. ","TWN":"從剛才通訊網就一直收到清道夫躍入的訊號。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아마 레플리카 함선들로 우릴 속이고 진짜 마타도르가 도망칠 시간을 벌 생각이겠죠.","JPN":"おそらくレプリカの艦船で私たちを騙して、本物のマタドールが逃げる時間を稼ぐつもりでしょう。","ENG":"I bet the Scavengers are using decoys to distract us while they run away.","TWN":"我猜他們應該是利用假的艦船來避人耳目，目的是要爭取逃跑的時間。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"다른 용병들은 너 나 할 것 없이 신호를 쫓아 다이브하고 있습니다.","JPN":"他の傭兵たちも皆信号を追ってダイブしています。","ENG":"Other mercenaries are Diving after the signals that they've detected.","TWN":"其他傭兵都一窩蜂地追著訊號躍入，"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저희처럼 의뢰주한테 독촉 받은 탓이겠지만요.","JPN":"私たちのように、依頼主から督促されたせいでしょう。","ENG":"They must have been pressured by the client, just like us.","TWN":"我想應該是因為跟我們一樣受到委託人的施壓吧？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"우선은 통신망에서 입수한 정보를 토대로 도주 중인 스캐빈저의 위치를 추정하려 합니다.","JPN":"まずは通信レーダーから入手した情報をもとに、逃走中のスカベンジャーの位置を推定しようと思います。","ENG":"For now, we're going to use the information on the communication network and narrow down the actual location of the Scavengers.","TWN":"我們目前打算利用通訊網接收到的資訊，來推測那些清道夫的位置。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"혹시 다른 정보를 입수하신다면……","JPN":"もし他の情報が手に入ったら……","ENG":"If you get ahold of different information—","TWN":"如果老闆有收到其他資訊的話……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":" 응?","JPN":"　ん？","ENG":" Mm?","TWN":"嗯？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"잠시만요. 사장님. 금방 돌아오겠습니다.","JPN":"お待ちください、社長。すぐ戻ります。","ENG":"Give me a moment, Boss. I'll be right back.","TWN":"老闆請稍等一下，我馬上回來。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"방금 연락은 뭐죠? 다이브를 할 수 없다고요?","JPN":"今の連絡は何ですか？　ダイブができないと？","ENG":"What was that? We can't Dive?","TWN":"剛剛那是什麼意思？沒辦法躍入？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"네. 먼저 간 함선들한테서 받은 좌표를 입력했는데 관제 시스템이 반응하지 않아서요.","JPN":"はい。先に出発した艦船から受けた座標を入力したんですけど、管制システムが反応しません。","ENG":"No. I've been trying to enter the coordinates from the ships that left before us. The control system wouldn't respond.","TWN":"是的，我們輸入了從其他艦船得到的座標，但控制系統都沒有反應。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"원인을 찾고 있지만 워낙 구형 시스템이라 시간이 오래 걸릴 것 같아요.","JPN":"原因を調査していますが、旧型システムなので時間がかかりそうです。","ENG":"I'm looking for the problem, but she's such an old model that it'll take a while to find it.","TWN":"目前正在確認原因，但因為系統非常老舊，所以會花上一些時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 그런 고물 함선을 돈 받고 빌려줬다는 거야?","JPN":"は？　こんなポンコツ艦船を金を貰って貸したってのか？","ENG":"What? You mean we paid for junk?","TWN":"什麼？收了錢竟然租給我們這個破爛古董艦船？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대체 어떤 자식이야? 내가 당장……!","JPN":"いったいどの業者だ？　俺が今すぐ……！","ENG":"Where's this rental company? I'm going to go—","TWN":"是哪個沒良心的傢伙？我要找他算……！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"Err?","TWN":"……嗯？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"왜, 왜 그래? 갑자기?","JPN":"な、なんだ？　どうした急に？","ENG":"W-what? What happened?","TWN":"怎…怎麼了？怎麼突然不說話？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"무슨…… 안 좋은 일이라도 생긴 건가요?","JPN":"何か……悪いお知らせですか？","ENG":"Did something bad happen?","TWN":"是發生了……什麼不好的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그게…….","JPN":"それが……","ENG":"Well...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다이브했던 함선들의 신호가 전부…… 사라졌어요.","JPN":"ダイブした艦船の信号が全部……消えました。","ENG":"The ships that Dove... All their signals are gone.","TWN":"那些躍入的艦船……訊號全都消失了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};